import { AbstractHelper } from "../AbstractHelper.js";
import { SpecificLinkQuery } from "./SpecificLinkQuery.js";
export class LinksHelper extends AbstractHelper {
  constructor(store, cacheKeys, whereCanonicalizer, orderByCanonicalizer, selectCanonicalizer) {
    super(store, cacheKeys);
    this.whereCanonicalizer = whereCanonicalizer;
    this.orderByCanonicalizer = orderByCanonicalizer;
    this.selectCanonicalizer = selectCanonicalizer;
  }
  getQuery(options) {
    const {
      apiName,
      type: sourceTypeKind
    } = options.srcType;
    const canonWhere = this.whereCanonicalizer.canonicalize(options.where ?? {});
    const canonOrderBy = this.orderByCanonicalizer.canonicalize(options.orderBy ?? {});
    const canonSelect = options.select && options.select.length > 0 ? this.selectCanonicalizer.canonicalize(options.select) : undefined;
    const linkCacheKey = this.cacheKeys.get("specificLink", apiName, sourceTypeKind, options.sourceUnderlyingObjectType, options.pk, options.linkName, canonWhere, canonOrderBy, canonSelect, options.$includeAllBaseObjectProperties ? true : undefined, options.resolveToObjectType ? true : undefined);
    return this.store.queries.get(linkCacheKey, () => {
      return new SpecificLinkQuery(this.store, this.store.subjects.get(linkCacheKey), linkCacheKey, options);
    });
  }
}