import { BehaviorSubject, connectable, map } from "rxjs";
import { additionalContext } from "../../../Client.js";
import { getBulkObjectLoader } from "../BulkObjectLoader.js";
import { Query } from "../Query.js";
import { tombstone } from "../tombstone.js";
import { extractRdpFieldNames } from "../utils/rdpFieldOperations.js";
import { RDP_CONFIG_IDX } from "./ObjectCacheKey.js";
export class ObjectQuery extends Query {
  #apiName;
  #pk;
  #defType;
  #select;
  #loadPropertySecurityMetadata;
  #includeAllBaseObjectProperties;
  #implementingTypes;
  constructor(store, subject, type, pk, cacheKey, opts, defType = "object", select, loadPropertySecurityMetadata, includeAllBaseObjectProperties) {
    super(store, subject, opts, cacheKey, process.env.NODE_ENV !== "production" ? store.client[additionalContext].logger?.child({}, {
      msgPrefix: `ObjectQuery<${cacheKey.otherKeys.map(x => JSON.stringify(x)).join(", ")}>`
    }) : undefined);
    this.#apiName = type;
    this.#pk = pk;
    this.#defType = defType;
    this.#select = select;
    this.#loadPropertySecurityMetadata = loadPropertySecurityMetadata ?? false;
    this.#includeAllBaseObjectProperties = includeAllBaseObjectProperties ?? false;
  }
  _createConnectable(subject) {
    return connectable(subject.pipe(map(x => {
      return {
        status: x.status,
        object: x.value,
        lastUpdated: x.lastUpdated,
        isOptimistic: x.isOptimistic
      };
    })), {
      connector: () => new BehaviorSubject({
        status: "init",
        object: undefined,
        lastUpdated: 0,
        isOptimistic: false
      })
    });
  }
  async _fetchAndStore() {
    if (process.env.NODE_ENV !== "production") {
      this.logger?.child({
        methodName: "_fetchAndStore"
      }).debug("calling _fetchAndStore");
    }

    // TODO: In the future, implement tracking of network requests to ensure
    // we're not making unnecessary network calls. This would need dedicated
    // tests separate from subscription notification tests.

    const rdpConfig = this.cacheKey.otherKeys[RDP_CONFIG_IDX];
    let obj;
    if (rdpConfig) {
      const miniDef = {
        type: this.#defType,
        apiName: this.#apiName
      };
      const fetched = await this.store.client(miniDef).withProperties(rdpConfig).fetchOne(this.#pk, {
        $includeRid: true,
        ...(this.#select && this.#select.length > 0 ? {
          $select: this.#select
        } : {}),
        $loadPropertySecurityMetadata: this.#loadPropertySecurityMetadata,
        ...(this.#includeAllBaseObjectProperties ? {
          $includeAllBaseObjectProperties: true
        } : {})
      });
      obj = fetched;
    } else {
      // Use batched loader for non-RDP objects (efficient batching)
      obj = await getBulkObjectLoader(this.store.client).fetch(this.#apiName, this.#pk, this.#defType, this.#select, this.#loadPropertySecurityMetadata, this.#includeAllBaseObjectProperties);
    }
    this.store.batch({}, batch => {
      this.writeToStore(obj, "loaded", batch, this.#select ? new Set(this.#select) : undefined);
    });
  }
  writeToStore(data, status, batch, selectFields, computedRdpFields) {
    const entry = batch.read(this.cacheKey);
    const rdpConfig = this.cacheKey.otherKeys[RDP_CONFIG_IDX];
    this.store.objectCacheKeyRegistry.register(this.cacheKey, this.#apiName, this.#pk, rdpConfig);

    // a caller passes the derived fields it computed. when it doesn't, default
    // to every derived field the key tracks.
    const computed = computedRdpFields ?? extractRdpFieldNames(rdpConfig);
    this.store.objects.propagateWrite(this.cacheKey, data, status, batch, selectFields, computed);
    return batch.read(this.cacheKey);
  }
  deleteFromStore(status, batch) {
    const rdpConfig = this.cacheKey.otherKeys[RDP_CONFIG_IDX];
    this.store.objectCacheKeyRegistry.register(this.cacheKey, this.#apiName, this.#pk, rdpConfig);
    this.store.objects.propagateWrite(this.cacheKey, tombstone, status, batch);
    return batch.read(this.cacheKey);
  }
  invalidateObjectType = async (objectType, changes) => {
    if (this.#defType === "object") {
      if (this.#apiName === objectType) {
        changes?.modified.add(this.cacheKey);
        return this.revalidate(true);
      }
      return;
    }
    if (!this.#implementingTypes) {
      const interfaceDef = {
        type: "interface",
        apiName: this.#apiName
      };
      const metadata = await this.store.client.fetchMetadata(interfaceDef);
      this.#implementingTypes = new Set(metadata.implementedBy ?? []);
    }
    if (this.#implementingTypes.has(objectType)) {
      changes?.modified.add(this.cacheKey);
      return this.revalidate(true);
    }
  };
}