import { compareNumericStrings } from "../compareNumericStrings.js";
import { PK_IDX } from "../object/ObjectCacheKey.js";
import { isStringEncodedNumericType, resolvePropertyType } from "../resolvePropertyType.js";

/**
 * Strategy interface for collection sorting
 */

/**
 * No-operation sorting strategy that preserves original order
 */
export class NoOpSortingStrategy {
  sortCacheKeys(objectCacheKeys, _batch) {
    return objectCacheKeys;
  }
}
/**
 * Sorting strategy for OrderBy clauses
 */
export class OrderBySortingStrategy {
  constructor(apiName, orderBy, derivedPropertyMetadata = {}) {
    this.apiName = apiName;
    this.orderBy = orderBy;
    this.derivedPropertyMetadata = derivedPropertyMetadata;
    this.sortFns = createOrderBySortFns(orderBy);
  }
  sortCacheKeys(objectCacheKeys, batch) {
    if (Object.keys(this.orderBy).length === 0) {
      return objectCacheKeys;
    }
    return objectCacheKeys.sort((a, b) => {
      for (const sortFn of this.sortFns) {
        const ret = sortFn(batch.read(a)?.value?.$as(this.apiName), batch.read(b)?.value?.$as(this.apiName), this.derivedPropertyMetadata);
        if (ret !== 0) {
          return ret;
        }
      }
      const aPk = a.otherKeys[PK_IDX];
      const bPk = b.otherKeys[PK_IDX];
      return aPk < bPk ? -1 : aPk > bPk ? 1 : 0;
    });
  }
}

/**
 * Creates sort functions for an orderBy clause
 * @param orderBy - The order by clause
 * @returns Array of sort functions
 */
export function createOrderBySortFns(orderBy) {
  return Object.entries(orderBy).map(([key, order]) => {
    return (a, b, derivedPropertyMetadata = {}) => {
      const aValue = a?.[key];
      const bValue = b?.[key];
      if (aValue == null && bValue == null) {
        return 0;
      }
      if (aValue == null) {
        return 1;
      }
      if (bValue == null) {
        return -1;
      }
      const m = order === "asc" ? -1 : 1;

      // `decimal`/`long` are wire-encoded as strings; comparing them with
      // `<` / `>` sorts them lexicographically ("10" < "9"), so compare them by
      // value when the declared type says they're numeric. The type comes from
      // the object/interface metadata on the holder, or -- for derived
      // properties -- from the runtime metadata passed alongside. The `?? b`
      // covers heterogeneous holders (e.g. an interface list backed by
      // different object types).
      if (typeof aValue === "string" && typeof bValue === "string" && isStringEncodedNumericType(resolvePropertyType(a, key, derivedPropertyMetadata) ?? resolvePropertyType(b, key, derivedPropertyMetadata))) {
        return -m * compareNumericStrings(aValue, bValue);
      }
      return aValue < bValue ? m : aValue > bValue ? -m : 0;
    };
  });
}